public double cumulativeProbability(double x) throws MathException {
    final double dev = x - mean;
    final double threshold = 40; // Default threshold can be made configurable
    try {
        if (dev < -threshold * standardDeviation) return 0;
        if (dev > threshold * standardDeviation) return 1;
        return 0.5 * (1.0 + Erf.erf((dev) / (standardDeviation * FastMath.sqrt(2.0))));
    } catch (MaxIterationsExceededException ex) {
        if (dev < -20 * standardDeviation) { // JDK 1.5 blows at 38
            return 0;
        } else if (dev > 20 * standardDeviation) {
            return 1;
        } else {
            throw ex;
        }
    }
}

public double cumulativeProbability(double x) throws MathException {
    final double dev = x - mean;
    final double scaledDev = dev / (standardDeviation * FastMath.sqrt(2.0));
    try {
        if (FastMath.abs(scaledDev) > 20) {
            // Use a more precise approximation for extreme values
            return 0.5 * (1.0 + FastMath.signum(scaledDev) * (1.0 - FastMath.exp(-scaledDev * scaledDev / 2.0) / FastMath.sqrt(FastMath.PI * 2.0)));
        } else {
            return 0.5 * (1.0 + Erf.erf(scaledDev));
        }
    } catch (MaxIterationsExceededException ex) {
        if (x < (mean - 20 * standardDeviation)) {
            return 0;
        } else if (x > (mean + 20 * standardDeviation)) {
            return 1;
        } else {
            throw ex;
        }
    }
}
